commits.content:
:host {
  display: block;
  padding: 1rem;
}

.form-control {
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  width: 100%;
}

.input-focus:focus {
  outline: none;
  border-color: #00b14f;
  box-shadow: 0 0 0 3px rgba(50, 118, 250, 0.2);
}

.btn {
  cursor: pointer;
  transition: background-color 0.2s;
}

.btn:hover {
  opacity: 0.9;
}
